from __future__ import annotations

from dataclasses import dataclass


@dataclass(frozen=True)
class SkillDefinition:
    id: str
    title: str
    mission: str
    inputs: tuple[str, ...]
    outputs: tuple[str, ...]
    triggers: tuple[str, ...]


