def definitions() -> tuple[SkillDefinition, ...]:
    return tuple(
        SkillDefinition(
            id=key,
            title=value["title"],
            mission=value["mission"],
            inputs=tuple(value["inputs"]),
            outputs=tuple(value["outputs"]),
            triggers=tuple(value["triggers"]),
        )
        for key, value in SKILLS.items()
    )
